<?php
namespace App\Domain\Hunts;use App\Domain\Characters\CharacterStatsCalculator;use App\Domain\Combat\CombatSimulator;use App\Domain\Combat\Factories\CharacterCombatantFactory;use App\Domain\Combat\Factories\MonsterCombatantFactory;use App\Domain\Hunts\Data\HuntResult;use App\Models\Character;use App\Models\Hunt;use App\Models\Zone;use Illuminate\Support\Collection;use Illuminate\Support\Facades\DB;use InvalidArgumentException;
final class HuntService {private $selector;private $calculator;private $characterFactory;private $monsterFactory;private $combat;public function __construct(WeightedMonsterSelector $s,CharacterStatsCalculator $c,CharacterCombatantFactory $cf,MonsterCombatantFactory $mf,CombatSimulator $combat){$this->selector=$s;$this->calculator=$c;$this->characterFactory=$cf;$this->monsterFactory=$mf;$this->combat=$combat;}public function start(Character $character,Zone $zone):HuntResult{if(!$character->exists||!$zone->exists)throw new InvalidArgumentException('Persisted entities required.');return DB::transaction(function()use($character,$zone){$started=now();$c=Character::whereKey($character->id)->lockForUpdate()->firstOrFail();$z=Zone::whereKey($zone->id)->lockForUpdate()->firstOrFail();$m=$this->selector->select($z,$c);$stats=$this->calculator->calculate($c);$result=$this->combat->simulate($this->characterFactory->make($c,$stats),$this->monsterFactory->make($m));$completed=now();$hunt=Hunt::create(['character_id'=>$c->id,'character_name'=>$c->name,'zone_id'=>$z->id,'zone_name'=>$z->name,'monster_id'=>$m->id,'monster_name'=>$m->name,'status'=>$result->status(),'rounds_count'=>$result->roundsCount(),'character_health_before'=>$result->characterInitialHealth(),'character_health_after'=>$result->characterFinalHealth(),'monster_health_before'=>$result->monsterInitialHealth(),'monster_health_after'=>$result->monsterFinalHealth(),'started_at'=>$started,'completed_at'=>$completed]);return $this->entry($hunt);},3);}public function history(Character $c,int $limit=50):Collection{return $c->hunts()->latest()->limit($limit)->get()->map(function($h){return$this->entry($h);});}public function detail(Character $c,$huntId):HuntResult{return$this->entry($c->hunts()->whereKey($huntId)->firstOrFail());}private function entry(Hunt $h){return new HuntResult($h->id,$h->character_id,$h->character_name,$h->zone_id,$h->zone_name,$h->monster_id,$h->monster_name,$h->status,$h->rounds_count,$h->character_health_before,$h->character_health_after,$h->monster_health_before,$h->monster_health_after,$h->started_at->toIso8601String(),$h->completed_at->toIso8601String());}}
